changeSet.sql:
ALTER TABLE allocations ENABLE ROW LEVEL SECURITY;
ALTER TABLE allocations FORCE ROW LEVEL SECURITY;

CREATE POLICY tenant_isolation_select ON allocations
    FOR SELECT
    USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL);

CREATE POLICY tenant_isolation_modify ON allocations
    FOR ALL
    USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)
    WITH CHECK (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL);
